namespace ErabliereApi.Test.Extension;

public class WeatherForecastModelMappingExtensionTest
{
    [Theory]
    [InlineData("sam., 18 avr.", "ddd, dd MMM")]
    public void DateFormatExploration(string date, string format)
    {
        var culture = new CultureInfo("fr-CA");

        var d = DateTime.ParseExact(date, format, culture, DateTimeStyles.AssumeLocal);

        Console.WriteLine(d.ToString(format));
    }

    [Fact]
    public void MapModelDaily_ShouldNotFailed_WhenValidInput()
    {
        var ds = JsonSerializer.Deserialize<GouvCAWeatherStationResponse[]>(INPUT);
        ds.ShouldNotBeNull();

        var weatherResponseStr = ds.ShouldHaveSingleItem().ToWeatherForecastResponse("fr-CA", "46.159,-70.779");
        var weatherInfo = JsonSerializer.Deserialize<WeatherForecastResponse>(weatherResponseStr);

        weatherInfo.ShouldNotBeNull();
        weatherInfo.Headline.ShouldNotBeNull();
        weatherInfo.Headline.EffectiveEpochDate.ShouldBe(1776513947);
        weatherInfo.Headline.EffectiveDate.ShouldBe(DateTimeOffset.Parse("2026-04-18T12:00:00 +00:00"));
        weatherInfo.DailyForecasts.ShouldNotBeNull().ShouldNotBeEmpty();
        var days = weatherInfo.DailyForecasts.Where(df => df.Day != null).Select(df => df.Day);
        var night = weatherInfo.DailyForecasts.Where(df => df.Night != null).Select(df => df.Night);
    }

    [Fact]
    public void MapModelHourly_ShouldNotFailed_WhenValidInput()
    {
        var ds = JsonSerializer.Deserialize<GouvCAWeatherStationResponse[]>(INPUT);
        ds.ShouldNotBeNull();

        var weatherResponseStr = ds.ShouldHaveSingleItem().ToHourlyWeatherForecastResponse("fr-CA");
        var weatherInfo = JsonSerializer.Deserialize<HourlyWeatherForecastResponse[]>(weatherResponseStr);

        weatherInfo.ShouldNotBeNull();
        weatherInfo.Length.ShouldBe(24);
    }

